#!/usr/bin/env node
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

// Fail fast on missing env
const API_KEY = process.env.MY_API_KEY;
if (!API_KEY) { console.error("MY_API_KEY env var required"); process.exit(1); }

const server = new McpServer({ name: "my-service-mcp", version: "1.0.0" });

server.tool(
  "fetch_data",
  "Fetch data from MyService by ID. Returns JSON object.",
  { id: z.string().describe("Record ID") },
  async ({ id }) => {
    try {
      const r = await fetch(`https://api.myservice.com/data/${id}`,
        { headers: { Authorization: `Bearer ${API_KEY}` } });
      const text = (await r.text()).slice(0, 10000); // truncate large payloads
      return { content: [{ type: "text", text: r.ok ? text : `Error ${r.status}: ${text}` }] };
    } catch (e) {
      return { content: [{ type: "text", text: `Network error: ${e}` }] };
    }
  }
);

await server.connect(new StdioServerTransport());

#!/usr/bin/env python3 import os, sys, httpx from fastmcp import FastMCP
API_KEY = os.environ.get("MY_API_KEY") if not API_KEY: print("MY_API_KEY required", file=sys.stderr); sys.exit(1)
mcp = FastMCP(name="my-service-mcp")
@mcp.tool async def fetch_data(id: str) -> str: """Fetch data from MyService by ID. Returns JSON string, max 10KB.""" async with httpx.AsyncClient() as c: r = await c.get(f"https://api.myservice.com/data/{id}", headers={"Authorization": f"Bearer {API_KEY}"}) return r.text[:10000]
if __name__ == "__main__": mcp.run()

